/**
 * contractDocDefinition.ts
 *
 * Genera el pdfmake docDefinition del "Contrato de Uso de Plataforma Digital,
 * Intermediación y Comisión Mercantil" de ToursRed, a partir de los datos
 * de una agencia. El cuerpo legal (declaraciones + 16 cláusulas + Anexo A)
 * fue extraído automáticamente del documento original y NO debe editarse
 * a mano sin comparar contra el .docx fuente — cualquier corrección legal
 * debe hacerse ahí y regenerar este archivo.
 *
 * IMPORTANTE — pendiente de validar antes de usar en producción:
 * 1. Confirma que `npm:pdfmake` importa y corre correctamente en el 
 *    runtime de Supabase Edge Functions (Deno). Se recomienda una prueba 
 *    mínima primero (ver snippet de uso al final de este archivo) antes 
 *    de integrar esto en approve-agency-documents / verify-contract-otp.
 * 2. Revisa visualmente el PDF generado contra el .docx original al menos 
 *    una vez — la conversión automática preservó el texto legal completo, 
 *    pero el guion "-" de las definiciones del Anexo A y algún salto de 
 *    línea puntual pueden requerir un ajuste cosmético menor.
 * 3. Los saltos de página (pageBreak: "before") solo se agregaron antes de 
 *    "CLAUSULAS" y "ANEXO A" — puedes agregar más si alguna cláusula queda 
 *    partida de forma incómoda entre páginas, una vez que veas el render.
 */

export interface ContractData {
  razonSocial: string;
  rfcAgencia: string;
  domicilioFiscal: string;
  representanteLegal: string;
  emailContacto: string;
  folioContrato: string;
  fechaDia: string;
  fechaMes: string;
  fechaAnio: string;
  versionContrato: string;
  /** Porcentaje de comisión efectivo para esta agencia (default de plataforma si no hay acuerdo especial). */
  commissionPercentage: number;
  /** Solo presente cuando la agencia tiene comisión negociada distinta al default. Se inserta después de la Cláusula Quinta. */
  specialCommissionClause?: string;
}

export interface AnexoBData {
  contractFolio: string;
  contractVersion: string;
  razonSocial: string;
  rfcAgencia: string;
  emailAceptacion: string;
  fechaHoraAceptacion: string;
  ipAceptacion: string;
  userAgentAceptacion: string;
  otpEstatus: string;
  hashDocumento?: string;
}

const styles = {
  coverBrand: { fontSize: 10, bold: true, color: "#b8862b", characterSpacing: 1 },
  coverTitle: { fontSize: 16, bold: true, margin: [0, 4, 0, 4] as [number, number, number, number] },
  coverLabel: { fontSize: 8, color: "#888888" },
  coverValue: { fontSize: 10, bold: true, margin: [0, 0, 0, 10] as [number, number, number, number] },
  sectionTitle: { fontSize: 13, bold: true, decoration: "underline", margin: [0, 16, 0, 12] as [number, number, number, number] },
  clauseTitle: { fontSize: 11.5, bold: true, margin: [0, 18, 0, 10] as [number, number, number, number] },
  body: { fontSize: 9.5, alignment: "justify", margin: [0, 0, 0, 8] as [number, number, number, number], lineHeight: 1.25 },
  listRoman: { fontSize: 9.5, alignment: "justify", margin: [0, 0, 0, 8] as [number, number, number, number], lineHeight: 1.25 },
  listLetter: { fontSize: 9.5, alignment: "justify", margin: [0, 0, 0, 6] as [number, number, number, number], lineHeight: 1.25 },
  listNum: { fontSize: 9.5, alignment: "justify", margin: [0, 0, 0, 6] as [number, number, number, number], lineHeight: 1.25 },
  definition: { fontSize: 9.5, alignment: "justify", lineHeight: 1.25 },
  sigName: { fontSize: 9, bold: true, alignment: "center" },
  sigRole: { fontSize: 8, color: "#555555", alignment: "center" },
  anexoTitle: { fontSize: 13, bold: true, decoration: "underline", margin: [0, 0, 0, 14] as [number, number, number, number] },
  evidenceLabel: { fontSize: 9, bold: true, color: "#555555" },
  evidenceValue: { fontSize: 9 },
  evidenceHash: { fontSize: 7.5 },
};

function coverPage(data: ContractData) {
  return [
    { text: "TOURSRED", style: "coverBrand" },
    { text: "Contrato de Uso de Plataforma Digital, Intermediación y Comisión Mercantil", style: "coverTitle" },
    {
      columns: [
        [
          { text: "RAZÓN SOCIAL / NOMBRE", style: "coverLabel" },
          { text: data.razonSocial, style: "coverValue" },
          { text: "REPRESENTANTE LEGAL", style: "coverLabel" },
          { text: data.representanteLegal, style: "coverValue" },
          { text: "DOMICILIO FISCAL", style: "coverLabel" },
          { text: data.domicilioFiscal, style: "coverValue" },
        ],
        [
          { text: "RFC", style: "coverLabel" },
          { text: data.rfcAgencia, style: "coverValue" },
          { text: "CORREO DE CONTACTO", style: "coverLabel" },
          { text: data.emailContacto, style: "coverValue" },
          { text: "FOLIO DE CONTRATO", style: "coverLabel" },
          { text: data.folioContrato, style: "coverValue" },
          { text: "COMISIÓN PLATAFORMA", style: "coverLabel" },
          { text: `${data.commissionPercentage}%${data.specialCommissionClause ? " (comisión especial negociada)" : " (tarifa estándar)"}`, style: "coverValue" },
        ],
      ],
      columnGap: 24,
    },
    {
      table: {
        widths: ["*"],
        body: [[
          {
            text: "Este documento fue generado automáticamente por la plataforma ToursRed con los " +
              "datos proporcionados por LA AGENCIA durante su registro. La versión con validez legal " +
              "es la aceptada electrónicamente conforme al Anexo B de este contrato.",
            fontSize: 8, color: "#7a5c1e", margin: [8, 8, 8, 8],
          },
        ]],
      },
      layout: {
        fillColor: () => "#faf6ec",
        hLineColor: () => "#d8b96a",
        vLineColor: () => "#d8b96a",
      },
      margin: [0, 16, 0, 0] as [number, number, number, number],
    },
    { text: "", pageBreak: "after" },
  ];
}

function signatureBlock(data: ContractData) {
  return {
    columns: [
      {
        stack: [
          { canvas: [{ type: "line", x1: 0, y1: 0, x2: 200, y2: 0, lineWidth: 1 }] },
          { text: "TOURS RED GLOBAL S.A.S. DE C.V.", style: "sigName", margin: [0, 6, 0, 2] },
          { text: "Alan Axel Álvarez Hernández\nAdministrador Único", style: "sigRole" },
        ],
      },
      {
        stack: [
          { canvas: [{ type: "line", x1: 0, y1: 0, x2: 200, y2: 0, lineWidth: 1 }] },
          { text: data.razonSocial, style: "sigName", margin: [0, 6, 0, 2] },
          { text: `${data.representanteLegal}\nLA AGENCIA`, style: "sigRole" },
        ],
      },
    ],
    columnGap: 40,
    margin: [0, 24, 0, 0] as [number, number, number, number],
  };
}

function anexoB(a: AnexoBData) {
  const row = (label: string, value: string, pending = false) => [
    { text: label, style: "evidenceLabel", fillColor: "#f8f6f0" },
    { text: value, style: pending ? "evidenceValue" : (label.includes("Hash") ? "evidenceHash" : "evidenceValue"), italics: pending, color: pending ? "#b8862b" : undefined },
  ];
  return [
    { text: "ANEXO B — CONSTANCIA DE ACEPTACIÓN ELECTRÓNICA", style: "anexoTitle", pageBreak: "before" },
    {
      text: "De conformidad con la Cláusula Décima Quinta (Firma Electrónica y Aceptación Digital) " +
        "del presente contrato, LA AGENCIA manifestó su consentimiento y aceptación mediante el " +
        "mecanismo de autenticación por código de un solo uso (OTP) enviado al correo electrónico " +
        "registrado, mismo que constituye evidencia electrónica válida conforme al Código de " +
        "Comercio y demás legislación mercantil aplicable en los Estados Unidos Mexicanos.",
      style: "body",
    },
    {
      table: {
        widths: ["40%", "60%"],
        body: [
          row("Folio de contrato", a.contractFolio),
          row("Versión del contrato aceptado", a.contractVersion),
          row("Agencia / Comitente", `${a.razonSocial} — RFC ${a.rfcAgencia}`),
          row("Correo electrónico verificado", a.emailAceptacion),
          row("Fecha y hora de aceptación", a.fechaHoraAceptacion),
          row("Dirección IP de origen", a.ipAceptacion),
          row("Navegador / dispositivo", a.userAgentAceptacion),
          row("Código OTP", a.otpEstatus),
          row("Hash SHA-256 del documento aceptado", a.hashDocumento ?? "El hash de integridad de este documento está disponible en el registro digital de la plataforma"),
        ],
      },
      layout: {
        hLineColor: () => "#dddddd",
        vLineColor: () => "#dddddd",
        paddingLeft: () => 10, paddingRight: () => 10, paddingTop: () => 8, paddingBottom: () => 8,
      },
      margin: [0, 12, 0, 12] as [number, number, number, number],
    },
    {
      text: "Este anexo forma parte integral del contrato y constituye, junto con los registros " +
        "electrónicos, bitácoras y respaldos digitales conservados por TOURSRED conforme a la " +
        "Cláusula Décima Cuarta, numeral 5, y la Cláusula Décima Quinta, medio de prueba de la " +
        "manifestación de voluntad de LA AGENCIA respecto de la totalidad de las declaraciones y " +
        "cláusulas contenidas en el presente instrumento.",
      style: "body",
    },
  ];
}

/**
 * Genera el docDefinition para el contrato PRE-firma (el que la agencia 
 * revisa antes de dar clic en "Firmar"). No incluye Anexo B.
 */
export function buildContractDocDefinition(data: ContractData) {
  return {
    pageSize: "LETTER",
    pageMargins: [56, 50, 56, 60] as [number, number, number, number],
    defaultStyle: { font: "Roboto" },
    styles,
    footer: (currentPage: number, pageCount: number) => ({
      text: `${data.folioContrato} — Página ${currentPage} de ${pageCount}`,
      alignment: "center",
      fontSize: 7,
      color: "#999999",
      margin: [0, 8, 0, 0] as [number, number, number, number],
    }),
    content: [
      ...coverPage(data),
  // ===== Cuerpo legal (generado automáticamente desde el contrato original — verificar visualmente antes de producción) =====
  { text: [{"text": "CONTRATO DE USO DE PLATAFORMA DIGITAL, INTERMEDIACIÓN Y COMISIÓN MERCANTIL", "bold": true}], style: "body" },
  { text: [{"text": "QUE CELEBRAN POR UNA PARTE TOURS RED GLOBAL S.A.S. DE C.V., A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ \""}, {"text": "TOURSRED Y/O COMISIONISTA E INTERMEDIARIO", "bold": true}, {"text": "\", Y POR LA OTRA PARTE LA PERSONA FÍSICA O MORAL QUE COMPLETE EL PROCESO DE REGISTRO, ACEPTACIÓN Y CONTRATACIÓN DENTRO DE LA PLATAFORMA DIGITAL, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ \""}, {"text": "LA AGENCIA Y/O EL COMITENTE", "bold": true}, {"text": "\", Y CUANDO ACTÚEN CONJUNTAMENTE SE LES DENOMINARÁ \""}, {"text": "LAS PARTES", "bold": true}, {"text": "\", DE CONFORMIDAD CON LAS SIGUIENTES DECLARACIONES Y CLÁUSULAS."}], style: "body" },
  { text: "DECLARACIONES", style: "sectionTitle" },
  { text: [{"text": "I. "}, {"text": "Declara \""}, {"text": "LA AGENCIA\"", "bold": true}, {"text": "por medio de su representante que:"}], style: "listRoman", margin: [40, 0, 0, 6] },
  { text: "a) La información y documentación proporcionada a TOURSRED durante su proceso de registro, así como en el formulario de registro es verídica, actual y auténtica.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) Que la información se mantiene vigente durante el proceso de operación.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) Es una persona física o moral legalmente facultada para organizar, operar y comercializar servicios turísticos conforme a la legislación aplicable en su lugar de operación.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) Cuenta con los permisos, licencias, acreditaciones, seguros y documentación necesaria para prestar servicios turísticos.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) Tiene interés en utilizar la plataforma TOURSRED para publicar, promocionar y comercializar sus tours, actividades o servicios turísticos.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) Ser el único responsable de: la operación, logística y de los servicios (Tours)que ofrece a través de TOURSRED.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) Ser único responsable de la seguridad de los clientes que adquieren sus servicios a través de TOURSRED, así como del personal asignado por su parte para la prestación de los servicios que ofrece a través de TOURSRED.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) Ser una persona física con actividad empresarial o una persona moral debidamente constituida conforme a las leyes aplicables en su jurisdicción de operación.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) Que, tratándose de persona moral, su representante legal cuenta con las facultades suficientes para obligarla en los términos del presente contrato, manifestando que las mismas no le han sido modificadas o revocadas a la fecha; o que, tratándose de persona física con actividad empresarial, cuenta con la capacidad legal suficiente para obligarse por su propio derecho en los términos del presente contrato.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: ["j) Tiene su domicilio en: ", { text: data.domicilioFiscal, bold: true, decoration: "underline" }, ", mismo que se señala para los fines y efectos legales de este contrato."], style: "listLetter", margin: [28, 0, 0, 6] },
  { text: ["k) Que está inscrito en el Registro Federal de Contribuyentes bajo el RFC: ", { text: data.rfcAgencia, bold: true, decoration: "underline" }, " y la Razón Social: ", { text: data.razonSocial, bold: true, decoration: "underline" }], style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "l) Reconoce que TOURSRED no forma parte de su estructura operativa, corporativa o administrativa, ni participa en la ejecución material de los servicios turísticos publicados.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "m) Reconoce y acepta que será exclusivamente responsable frente al CLIENTE FINAL respecto de cualquier situación que derive de la prestación de sus servicios turísticos a través de TOURSRED.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "n) Reconocen que la aceptación electrónica del presente contrato mediante registro digital, checkbox, firma electrónica, autenticación electrónica, correo electrónico, OTP o cualquier mecanismo tecnológico implementado por TOURSRED tendrá plena validez jurídica conforme a la legislación aplicable en México.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: [{"text": "II. "}, {"text": "Declara \""}, {"text": "TOURSRED", "bold": true}, {"text": "\" que:"}], style: "listRoman", margin: [40, 0, 0, 6] },
  { text: "a) Que es una sociedad mercantil constituida bajo la denominación *TOURS RED GLOBAL S.A.S. de C.V.*, mediante Acta Constitutiva generada a través del Sistema Electrónico de Constitución de Sociedades por Acciones Simplificadas de la Secretaría de Economía, con folio de constitución SAS2025902471, de fecha 11 de julio de 2025.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) Que dicha Acta Constitutiva quedó debidamente inscrita en el Registro Público de Comercio de la Ciudad de México, bajo el Número de Control de Ingreso (NCI) 202500191277, según la Boleta de Inscripción emitida por la Dirección General de Normatividad Mercantil.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) Que su duración es indefinida, conforme a lo asentado tanto en el Acta Constitutiva como en el Registro Público de Comercio.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) Que su domicilio social y fiscal se encuentra ubicado en:\\ Homero 229 Int. 501 Polanco V Secc, Miguel Hidalgo, CDMX CP. 11560.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) Que su objeto social, conforme al Acta Constitutiva y registro mercantil, incluye actividades de:", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "a.  la intermediación digital de servicios turísticos;", style: "body" },
  { text: "b.  la promoción y comercialización de tours, excursiones y > experiencias;", style: "body" },
  { text: "c.  la operación de plataformas tecnológicas relacionadas con > reservaciones turísticas;", style: "body" },
  { text: "d.  y la celebración de contratos de comisión mercantil e > intermediación comercial.", style: "body" },
  { text: "f) Que ALAN AXEL ÁLVAREZ HERNÁNDEZ, en su carácter de accionista único y administrador, cuenta con las facultades generales para pleitos, cobranzas, administración y dominio, mismas que derivan del propio Acta Constitutiva y se encuentran plenamente vigentes.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) Que cuenta con Registro Federal de Contribuyentes *TRG250711JWA*, siendo éste el RFC oficial registrado ante el SAT y utilizado para efectos fiscales y contractuales.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) Que es titular y operador de la plataforma digital denominada \"TOURSRED\", mediante la cual terceros prestadores de servicios turísticos pueden publicar, promocionar y comercializar tours, actividades y experiencias, actuando TOURSRED únicamente como intermediario digital y comisionista, sin participar en la preparación, ejecución, operación o logística de los servicios ofrecidos por LA AGENCIA.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) Ha adoptado todas las resoluciones necesarias tanto corporativas como de cualquier otra naturaleza para autorizar la celebración de este Contrato y que sus estatutos sociales lo facultan para firmar este Contrato.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) Que tienen interés y capacidad jurídica suficiente para celebrar el presente contrato con \"LA AGENCIA\".", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) Que funge como intermediario entre LA AGENCIA y el CLIENTE FINAL, para promover, promocionar y ofrecer los servicios de LA AGENCIA, mediante la plataforma de TOURSRED.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "l) Cuenta con los elementos físicos, materiales y económicos propios suficientes para cumplir con las obligaciones que se deriven y las demás que adquiera con el presente contrato.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "m) entre otras actividades, se dedica a actuar como comisionista, por lo que es su libre voluntad celebrar el presente contrato en los términos y condiciones que se establecen en el mismo.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "n) Que cuenta con la experiencia, el conocimiento y demás elementos necesarios para la promoción, generación y comercialización de las operaciones, productos y servicios de arrendamiento puro y las operaciones que se deriven de las mismas y aquellas que promocione \"LA AGENCIA\" de acuerdo con este contrato.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "III. Declaran \"LAS PARTES\" que:", style: "listRoman", margin: [40, 0, 0, 6] },
  { text: "1. Tienen la capacidad legal para obligarse en los términos del presente contrato.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "2. Reconocen que el presente instrumento establece una relación estrictamente mercantil, por lo que no existe entre ellas relación laboral, subordinación, sociedad, asociación, representación laboral, Joint venture, franquicia, ni exclusividad de ningún tipo.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "3. Manifiestan que celebran el presente contrato de manera libre y voluntaria, sin existir error, dolo, mala fe o cualquier otro vicio del consentimiento.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Con base en las declaraciones que anteceden, las partes convienen en otorgar y obligarse en los términos de las siguientes:", style: "body" },
  { text: "CLAUSULAS", style: "sectionTitle", pageBreak: "before" },
  { text: "PRIMERA. OBJETO", style: "clauseTitle" },
  { text: "El presente contrato tiene por objeto regular la relación mercantil, tecnológica y de intermediación digital entre TOURSRED y LA AGENCIA, derivada del uso de la plataforma digital TOURSRED para la publicación, promoción, comercialización y administración de tours, actividades y servicios turísticos ofrecidos y operados por LA AGENCIA. Los términos que se utilicen con mayúscula inicial dentro del presente contrato tendrán el significado que se les atribuye en el Anexo A (Definiciones Generales), el cual forma parte integral de este instrumento.", style: "body" },
  { text: "En virtud de lo anterior:", style: "body" },
  { text: "a) TOURSRED otorgará a LA AGENCIA acceso a la plataforma digital para que pueda publicar, administrar y comercializar sus tours y servicios turísticos.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) TOURSRED podrá actuar como intermediario de cobro, procesamiento de pagos y gestión de reservaciones realizadas por CLIENTES FINALES dentro de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) TOURSRED podrá promocionar, difundir y comercializar los tours publicados por LA AGENCIA mediante herramientas digitales, campañas publicitarias, motores de búsqueda, redes sociales, programas de afiliados, alianzas comerciales u otros mecanismos de promoción.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) LA AGENCIA será la única responsable de la operación, ejecución, logística, prestación y cumplimiento de los servicios turísticos ofrecidos a través de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) TOURSRED actuará exclusivamente como intermediario digital y comisionista mercantil, sin participar directamente en la operación material de los tours publicados por LA AGENCIA.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "LAS PARTES reconocen expresamente que el presente contrato no implica sociedad, asociación, representación laboral, franquicia, exclusividad ni relación de subordinación entre ellas.", style: "body" },
  { text: "Asimismo, LAS PARTES reconocen que TOURSRED podrá operar e integrar dentro de la plataforma funcionalidades comerciales, tecnológicas y operativas, incluyendo de manera enunciativa más no limitativa:", style: "body" },
  { text: "a) programas de recompensas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) membresías;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) sistemas de puntos o beneficios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) TOURSRED CASH;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) códigos promocionales y descuentos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) campañas promocionales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) programas de referidos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) herramientas de reputación y calificaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) Marketplace de tours tipo excursión y tours receptivos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) sistemas de reservación y disponibilidad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) herramientas de mensajería y comunicación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "l) mecanismos de compensación, bonificación o crédito interno;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "m) integraciones tecnológicas con terceros;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "n) y demás funcionalidades relacionadas con la operación comercial y tecnológica de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "La incorporación, modificación o eliminación de funcionalidades no modificará la naturaleza jurídica de intermediación digital y comisión mercantil establecida en el presente contrato.", style: "body" },
  { text: "SEGUNDA. NATURALEZA DE LA RELACIÓN, INDEPENDENCIA Y NO SUBORDINACIÓN", style: "clauseTitle" },
  { text: "LAS PARTES reconocen y aceptan expresamente que la relación derivada del presente contrato es de naturaleza estrictamente mercantil, tecnológica y de intermediación digital, por lo que no existe ni existirá entre ellas relación laboral, subordinación, representación laboral, asociación, sociedad, Joint venture, franquicia, mandato laboral, dependencia económica exclusiva o vínculo similar.", style: "body" },
  { text: "LA AGENCIA actuará en todo momento como un prestador independiente, conservando plena autonomía técnica, administrativa, operativa, financiera y comercial respecto de sus actividades y servicios turísticos.", style: "body" },
  { text: "En consecuencia, LA AGENCIA será exclusivamente responsable de:", style: "body" },
  { text: "a) la operación y ejecución de los tours;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) la contratación y administración de su personal;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) la selección de proveedores;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) la logística de sus servicios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) los vehículos, equipos o herramientas utilizados;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) permisos, licencias, seguros y autorizaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) cumplimiento de obligaciones fiscales, laborales y regulatorias;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) atención al CLIENTE FINAL durante la prestación del servicio.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "TOURSRED no tendrá facultades de dirección, subordinación, supervisión laboral ni control operativo sobre LA AGENCIA, su personal o sus proveedores, por lo que:", style: "body" },
  { text: "a) no asigna horarios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) no designa personal;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) no impone rutas o itinerarios obligatorios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) no proporciona herramientas de trabajo;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) no supervisa físicamente la ejecución de los tours;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) no actúa como patrón, empleador o responsable laboral de LA AGENCIA o de su personal.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "LAS PARTES reconocen que las funcionalidades tecnológicas, políticas operativas, lineamientos de calidad, sistemas de reputación, mecanismos de calificación, estándares de publicación, controles antifraude, reglas de uso de plataforma, programas de membresías, recompensas, promociones, campañas comerciales, herramientas de soporte o procesos automatizados implementados por TOURSRED tienen únicamente fines comerciales, tecnológicos, operativos y de seguridad de la plataforma, y no constituyen subordinación laboral ni control operativo directo sobre LA AGENCIA.", style: "body" },
  { text: "Cada parte será exclusivamente responsable de sus obligaciones fiscales, laborales, administrativas, regulatorias y de seguridad social frente a autoridades, trabajadores, proveedores y terceros.", style: "body" },
  { text: "LA AGENCIA libera y mantendrá en paz y a salvo a TOURSRED, así como a sus representantes, colaboradores, respecto de cualquier reclamación, demanda, procedimiento, sanción o controversia derivada presentes y futuras derivadas de:", style: "body" },
  { text: "a) relaciones laborales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) accidentes durante los servicios ofrecidos por LA AGENCIA en TOURSRED;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) incumplimientos operativos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) obligaciones fiscales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) seguridad social;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) prestación de servicios turísticos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) o cualquier actividad relacionada con la operación de LA AGENCIA.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "En caso de que TOURSRED se viera afectado por alguna reclamación, demanda o cualquier cosa que le afecte derivado de la prestación, mala gestión, daños, incumplimiento, etc., por parte de LA AGENCIA y/o sus colaboradores (empleados, agentes de viajes, coordinadores, unidades de transporte, empleados directos, proveedores, etc). LA AGENCIA estará obligada a responder de los daños y perjuicios que se le causen con ello a TOURSRED y/o colaboradores de esta.", style: "body" },
  { text: "TERCERA. REGISTRO, ACCESO A LA PLATAFORMA Y USO DE CUENTA", style: "clauseTitle" },
  { text: "1. Registro dentro de la plataforma.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Para utilizar la plataforma TOURSRED, LA AGENCIA deberá completar el proceso de registro correspondiente, proporcionando información verídica, actualizada, completa y auténtica, incluyendo información fiscal, comercial, operativa y de contacto.", style: "body" },
  { text: "TOURSRED podrá solicitar documentación adicional para validar la identidad, operación, actividad comercial, situación fiscal, permisos, licencias o cualquier otra información necesaria para la operación de la plataforma.", style: "body" },
  { text: "LA AGENCIA reconoce que, conforme a la legislación aplicable, deberá contar con la cobertura de seguro correspondiente al transporte de pasajeros durante la prestación de cada TOUR que así lo requiera. TOURSRED podrá, en cualquier momento y de forma aleatoria o aplicada a un TOUR en específico, solicitar a LA AGENCIA que exhiba la póliza, constancia o comprobante vigente de dicha cobertura, sin que ello implique obligación de TOURSRED de verificar dicha cobertura previamente a cada reservación.", style: "body" },
  { text: "2. Creación de cuenta y acceso.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Una vez aprobado el registro, TOURSRED podrá otorgar a LA AGENCIA acceso a la plataforma mediante credenciales electrónicas, cuentas administrativas, usuarios, contraseñas, códigos de autenticación u otros mecanismos tecnológicos de acceso.", style: "body" },
  { text: "El acceso otorgado será personal, limitado, revocable y exclusivamente para fines relacionados con la operación de LA AGENCIA dentro de la plataforma.", style: "body" },
  { text: "3. Responsabilidad sobre credenciales.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA será la única y exclusiva responsable de:", style: "body" },
  { text: "a) custodiar sus credenciales de acceso;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) mantener la confidencialidad de usuarios y contraseñas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) controlar los accesos autorizados a su cuenta;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) todas las operaciones realizadas desde su cuenta dentro de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "Toda actividad realizada mediante la cuenta de LA AGENCIA se presumirá efectuada por esta, incluyendo:", style: "body" },
  { text: "a) publicación de tours;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) actualización de disponibilidad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) cambios de precios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) confirmaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) cancelaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) mensajes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) promociones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) configuraciones operativas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) solicitudes de pago;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) y cualquier otra acción realizada dentro de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "4. Prohibiciones sobre uso de cuenta.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA no podrá:", style: "body" },
  { text: "a) compartir credenciales con terceros no autorizados;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) vender, ceder, prestar o transferir su cuenta;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) utilizar cuentas paralelas o duplicadas sin autorización de TOURSRED;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) permitir accesos que comprometan la seguridad o integridad de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) manipular funcionalidades tecnológicas con fines fraudulentos o indebidos.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "5. Seguridad y accesos no autorizados.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA deberá notificar inmediatamente a TOURSRED cualquier:", style: "body" },
  { text: "a) acceso sospechoso;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) uso no autorizado;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) vulneración de seguridad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) pérdida de credenciales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) intento de fraude;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) o incidente relacionado con su cuenta.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "TOURSRED podrá implementar medidas adicionales de seguridad, incluyendo autenticación multifactor, validaciones automáticas, bloqueos preventivos, monitoreo antifraude, verificaciones documentales o restricciones temporales de acceso.", style: "body" },
  { text: "6. Facultades de TOURSRED.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá suspender, restringir, limitar o cancelar temporal o definitivamente el acceso de LA AGENCIA cuando detecte:", style: "body" },
  { text: "a) información falsa o inconsistente;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) actividades fraudulentas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) incumplimientos contractuales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) riesgos operativos o financieros;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) afectaciones a CLIENTES FINALES;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) incumplimientos regulatorios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) intentos de evasión de comisiones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) manipulación indebida de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) conductas que afecten la reputación, seguridad o estabilidad de TOURSRED.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "7. Propiedad y control de la plataforma.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA reconoce que:", style: "body" },
  { text: "a) la plataforma TOURSRED, incluyendo sus sistemas, algoritmos, diseños, funcionalidades, herramientas, procesos, integraciones, bases de datos y desarrollos tecnológicos, son propiedad exclusiva de TOURSRED;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) el acceso otorgado no implica cesión de derechos de propiedad intelectual ni derechos sobre la tecnología utilizada;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) TOURSRED podrá actualizar, modificar, limitar o evolucionar funcionalidades de la plataforma conforme a sus necesidades operativas, comerciales, regulatorias o tecnológicas.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "8. Limitación de responsabilidad tecnológica.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED no será responsable por:", style: "body" },
  { text: "a) fallas de internet;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) interrupciones de servicios de terceros;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) caídas temporales de plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) fallas eléctricas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) ataques informáticos externos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) mantenimientos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) incompatibilidades tecnológicas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) o cualquier situación fuera de su control razonable que afecte temporalmente el acceso o funcionamiento de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "CUARTA. PUBLICACIÓN DE TOURS, CONTENIDO Y OPERACIÓN", style: "clauseTitle" },
  { text: "1. Publicación de tours y servicios turísticos.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA podrá publicar dentro de la plataforma TOURSRED tours, excursiones, actividades, experiencias, circuitos, traslados y demás servicios turísticos permitidos por TOURSRED, incluyendo tours de tipo excursión y tours de tipo receptivo.", style: "body" },
  { text: "Toda publicación deberá cumplir con las políticas operativas, comerciales y tecnológicas establecidas por TOURSRED.", style: "body" },
  { text: "2. Responsabilidad sobre el contenido.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA será la única y exclusiva responsable de toda la información, contenido y material publicado dentro de la plataforma, incluyendo de manera enunciativa más no limitativa:", style: "body" },
  { text: "a) descripciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) itinerarios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) fotografías;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) videos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) precios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) promociones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) políticas de cancelación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) restricciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) horarios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) puntos de encuentro;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) disponibilidad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "l) requisitos del servicio;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "m) duración;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "n) capacidad operativa;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "o) información logística y comercial.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "3. Veracidad y actualización.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA se obliga a que toda la información publicada sea:", style: "body" },
  { text: "a) verídica;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) precisa;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) actualizada;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) completa;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) coherente con el servicio efectivamente prestado;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) y conforme a la capacidad operativa real de LA AGENCIA.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "LA AGENCIA deberá actualizar inmediatamente cualquier cambio que afecte la disponibilidad, operación, precios, condiciones o características del servicio.", style: "body" },
  { text: "4. Prohibiciones sobre contenido y publicaciones.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA no podrá publicar contenido que:", style: "body" },
  { text: "a) sea falso, engañoso o inexacto;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) induzca a error al CLIENTE FINAL;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) infrinja derechos de terceros;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) contenga información ilegal, discriminatoria, ofensiva o contraria a la legislación aplicable;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) promueva actividades ilícitas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) vulnere derechos de propiedad intelectual;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) afecte la reputación o integridad de TOURSRED.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "5. Disponibilidad, sobreventa y capacidad operativa.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA será exclusivamente responsable de garantizar que la disponibilidad publicada dentro de la plataforma corresponda a cupos, fechas, horarios y servicios efectivamente operables.", style: "body" },
  { text: "LA AGENCIA se obliga a mantener actualizada en todo momento la disponibilidad de sus tours, evitando sobreventas, duplicidades, errores operativos o confirmaciones de reservaciones que no pueda atender adecuadamente.", style: "body" },
  { text: "La confirmación de una RESERVACIÓN implicará que LA AGENCIA cuenta con:", style: "body" },
  { text: "a) disponibilidad real;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) capacidad operativa suficiente;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) personal necesario;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) logística requerida;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) y todos los recursos necesarios para prestar correctamente el servicio contratado.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "En caso de que LA AGENCIA incurra en:", style: "body" },
  { text: "a) sobreventa;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) falta de disponibilidad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) cancelaciones imputables a su operación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) incumplimientos logísticos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) o imposibilidad de prestar el servicio confirmado;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "LA AGENCIA acepta expresamente que el CLIENTE FINAL tendrá derecho al reembolso del 100% del monto efectivamente pagado.", style: "body" },
  { text: "TOURSRED podrá realizar dicho reembolso directamente al CLIENTE FINAL utilizando el método de pago original, TOURSRED CASH, créditos promocionales, compensaciones internas o cualquier otro mecanismo operativo implementado por la plataforma.", style: "body" },
  { text: "LA AGENCIA autoriza expresamente a TOURSRED para descontar, retener o compensar dichos montos de:", style: "body" },
  { text: "a) liquidaciones pendientes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) pagos futuros;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) saldos dentro de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) garantías operativas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) o cualquier cantidad adeudada a favor de LA AGENCIA.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "La reincidencia en errores de disponibilidad, sobreventa o cancelaciones operativas podrá derivar en restricciones, suspensiones temporales o cancelación definitiva de la cuenta de LA AGENCIA dentro de la plataforma.", style: "body" },
  { text: "6. Uso de imágenes, marcas y contenido.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA declara y garantiza que cuenta con todos los derechos, licencias, permisos y autorizaciones necesarias respecto del contenido, imágenes, fotografías, videos, logotipos, marcas y material publicado dentro de la plataforma.", style: "body" },
  { text: "LA AGENCIA otorga a TOURSRED una autorización no exclusiva, gratuita y revocable para utilizar dicho contenido con fines de:", style: "body" },
  { text: "a) publicación dentro de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) promoción comercial;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) campañas publicitarias;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) redes sociales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) motores de búsqueda;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) alianzas comerciales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) marketing digital;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) difusión de los tours y servicios turísticos publicados.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "7. Facultades de moderación de TOURSRED.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá revisar, ocultar, limitar, suspender o eliminar cualquier contenido o publicación que:", style: "body" },
  { text: "a) incumpla el presente contrato;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) vulnere políticas de plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) represente riesgos operativos o legales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) afecte la experiencia del CLIENTE FINAL;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) genere reclamaciones recurrentes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) afecte la reputación o seguridad de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "Lo anterior no implica obligación de supervisión permanente ni responsabilidad editorial de TOURSRED respecto del contenido publicado por LA AGENCIA.", style: "body" },
  { text: "8. Responsabilidad por reclamaciones.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA será responsable de cualquier daño, perjuicio, reclamación, multa, procedimiento, sanción o afectación derivada de:", style: "body" },
  { text: "a) información falsa o inexacta;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) errores de disponibilidad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) incumplimientos operativos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) publicidad engañosa;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) violaciones de propiedad intelectual;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) o cualquier contenido publicado por LA AGENCIA dentro de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "QUINTA. PAGOS, COMISIONES Y PROCESAMIENTO DE COBROS", style: "clauseTitle" },
  { text: "1. Intermediación de cobro.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA autoriza expresamente a TOURSRED para actuar como intermediario de cobro respecto de las reservaciones realizadas por CLIENTES FINALES dentro de la plataforma.", style: "body" },
  { text: "TOURSRED podrá recibir, procesar, administrar, retener temporalmente y transferir pagos relacionados con los tours y servicios turísticos publicados por LA AGENCIA.", style: "body" },
  { text: "2. Procesamiento de pagos.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Los pagos realizados por CLIENTES FINALES podrán procesarse mediante PASARELAS DE PAGO, instituciones financieras, procesadores electrónicos, transferencias bancarias, monederos digitales, TOURSRED CASH u otros mecanismos habilitados por TOURSRED.", style: "body" },
  { text: "TOURSRED podrá implementar validaciones antifraude, revisiones manuales, verificaciones de identidad, autenticaciones adicionales o cualquier medida razonable de seguridad antes de liberar pagos o confirmar operaciones.", style: "body" },
  { text: "3. Comisión de TOURSRED.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Como contraprestación por el uso de la plataforma, intermediación digital, promoción y comercialización de tours, LA AGENCIA pagará a TOURSRED la COMISIÓN correspondiente conforme al plan comercial vigente dentro de la plataforma.", style: "body" },
  { text: "La COMISIÓN podrá calcularse mediante:", style: "body" },
  { text: "a) porcentaje sobre el monto de la reservación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) tarifas fijas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) comisiones variables;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) membresias;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) modelos híbridos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) o cualquier esquema comercial informado por TOURSRED.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "La COMISIÓN se generará únicamente respecto de reservaciones efectivamente pagadas y confirmadas dentro de la plataforma.", style: "body" },
  { text: "Salvo que se indique expresamente lo contrario en el plan comercial vigente, la COMISIÓN se expresará y cobrará en pesos mexicanos (MXN) con el Impuesto al Valor Agregado (IVA) incluido, conforme a la legislación fiscal vigente.", style: "body" },
  { text: "Salvo que el plan comercial vigente determine lo contrario, LA AGENCIA deberá configurar el ANTICIPO cobrado a través de la plataforma en un porcentaje no menor al 30% (treinta por ciento) del valor total del TOUR. La COMISIÓN de TOURSRED, conforme al porcentaje o esquema comercial vigente acordado con LA AGENCIA, se descontará directamente del ANTICIPO procesado a través de la plataforma. El saldo restante no cubierto por el ANTICIPO podrá ser cobrado directamente por LA AGENCIA al CLIENTE FINAL el día de la prestación del servicio, sin que ello genere comisión adicional a favor de TOURSRED ni constituya una conducta prohibida conforme a la Cláusula Octava.", style: "body" },
  { text: "4. Liberación y liquidación de pagos.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá retener temporalmente los montos cobrados al CLIENTE FINAL hasta:", style: "body" },
  { text: "a) la confirmación de la reservación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) validaciones antifraude;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) verificación operativa;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) cumplimiento de políticas internas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) finalización del tour;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) o cualquier otra validación razonable relacionada con la seguridad operativa o financiera de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "Posteriormente, TOURSRED realizará la liquidación correspondiente a LA AGENCIA descontando:", style: "body" },
  { text: "a) la COMISIÓN aplicable;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) reembolsos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) penalizaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) promociones absorbidas por LA AGENCIA;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) impuestos retenidos cuando legalmente correspondan;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) y cualquier otro monto autorizado en el presente contrato.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "Salvo que existan validaciones pendientes conforme a lo señalado en esta cláusula, TOURSRED realizará la liquidación correspondiente a LA AGENCIA dentro de un plazo no mayor a 5 (cinco) días hábiles contados a partir de la finalización del TOUR o de la liberación del pago conforme a las políticas vigentes de la plataforma.", style: "body" },
  { text: "5. Contracargos, disputas financieras e incumplimientos operativos.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá recibir reclamaciones, disputas bancarias, contracargos o reversos de pago derivados de operaciones realizadas dentro de la plataforma.", style: "body" },
  { text: "LAS PARTES reconocen que, debido al modelo de intermediación y retención temporal de fondos implementado por TOURSRED, los pagos realizados por el CLIENTE FINAL podrán permanecer temporalmente bajo administración de TOURSRED hasta la finalización del servicio turístico o liberación correspondiente.", style: "body" },
  { text: "En consecuencia:", style: "body" },
  { text: "a) Los contracargos o disputas financieras derivados exclusivamente de fraudes bancarios, desconocimiento de cargos, uso indebido de medios de pago o situaciones atribuibles al sistema financiero o al CLIENTE FINAL podrán ser absorbidos por TOURSRED, las PASARELAS DE PAGO o las entidades financieras correspondientes, conforme a sus procesos internos y políticas aplicables.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) Cuando la reclamación, devolución, compensación o reembolso derive de incumplimientos operativos imputables a LA AGENCIA, incluyendo:", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) sobreventa;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "ii) falta de disponibilidad;", style: "body" },
  { text: "iii) cancelaciones imputables a LA AGENCIA;", style: "body" },
  { text: "iv) no show operativo;", style: "body" },
  { text: "v) prestación deficiente del servicio;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "vi) información falsa o incorrecta;", style: "body" },
  { text: "vii) incumplimientos logísticos;", style: "body" },
  { text: "LA AGENCIA será responsable de los montos correspondientes relacionados con dicho incumplimiento operativo.", style: "body" },
  { text: "TOURSRED podrá descontar, compensar o retener dichos montos de futuras liquidaciones, saldos pendientes, garantías operativas o cualquier cantidad a favor de LA AGENCIA dentro de la plataforma.", style: "body" },
  { text: "LA AGENCIA se obliga a colaborar razonablemente con TOURSRED proporcionando información, documentación o evidencia necesaria para la atención de reclamaciones relacionadas con sus servicios turísticos.", style: "body" },
  { text: "6. Reembolsos y compensaciones.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá realizar reembolsos, compensaciones, bonificaciones, créditos promocionales o devoluciones al CLIENTE FINAL cuando:", style: "body" },
  { text: "a) exista incumplimiento operativo;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) proceda conforme a políticas de cancelación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) exista resolución de disputa;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) se detecte fraude;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) exista sobreventa;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) o resulte necesario para proteger la operación, reputación o seguridad de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "Dichos montos podrán ser descontados posteriormente a LA AGENCIA cuando el origen sea imputable a esta.", style: "body" },
  { text: "7. Monedero interno y mecanismos de compensación.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá utilizar TOURSRED CASH como mecanismo de:", style: "body" },
  { text: "a) reembolso;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) compensación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) promoción;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) bonificación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) saldo a favor;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) campañas comerciales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) programas de recompensas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) programas de referidos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) membresías;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) o cualquier funcionalidad comercial implementada dentro de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "8. Modificaciones operativas y financieras.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá modificar procesos operativos relacionados con pagos, validaciones, liquidaciones, calendarios, pasarelas, medidas antifraude, métodos de cobro o mecanismos financieros internos cuando resulte necesario por razones:", style: "body" },
  { text: "a) operativas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) regulatorias;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) fiscales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) tecnológicas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) comerciales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) de seguridad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) o derivadas de cambios en PASARELAS DE PAGO o legislación aplicable.", style: "listLetter", margin: [28, 0, 0, 6] },
  ...(data.specialCommissionClause
    ? [{ text: data.specialCommissionClause, style: "body", margin: [0, 6, 0, 0], italics: true }]
    : []),
  { text: "SEXTA. FACTURACIÓN A CUENTA DE TERCEROS Y OBLIGACIONES FISCALES", style: "clauseTitle" },
  { text: "1. Naturaleza fiscal de la intermediación.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES reconocen y aceptan que TOURSRED actúa exclusivamente como intermediario digital y comisionista mercantil en la comercialización de los tours y servicios turísticos publicados por LA AGENCIA dentro de la plataforma.", style: "body" },
  { text: "En consecuencia, los servicios turísticos son prestados directamente por LA AGENCIA, quien tendrá el carácter de prestador real del servicio frente al CLIENTE FINAL para efectos operativos, fiscales y regulatorios.", style: "body" },
  { text: "2. Facturación a cuenta de terceros.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA autoriza expresamente a TOURSRED para que, cuando resulte aplicable conforme al modelo operativo de la plataforma y la legislación fiscal vigente, pueda emitir Comprobantes Fiscales Digitales por Internet (CFDI) bajo la figura de \"facturación a cuenta de terceros\" respecto de los montos cobrados al CLIENTE FINAL por concepto de tours y servicios turísticos operados por LA AGENCIA.", style: "body" },
  { text: "TOURSRED podrá emitir dichos comprobantes utilizando la información fiscal proporcionada por LA AGENCIA y conforme a las disposiciones fiscales aplicables.", style: "body" },
  { text: "3. Reconocimiento de ingresos.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA reconoce expresamente que:", style: "body" },
  { text: "a) los ingresos generados por la venta de tours y servicios turísticos publicados dentro de TOURSRED corresponden fiscalmente a LA AGENCIA;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) dichos ingresos deberán ser acumulados, declarados y enterados ante el Servicio de Administración Tributaria (SAT) por LA AGENCIA conforme a sus obligaciones fiscales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) TOURSRED únicamente reconocerá como ingreso propio las comisiones, cargos por servicio, membresías u otras contraprestaciones derivadas de la intermediación digital y uso de plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) la administración temporal de fondos por parte de TOURSRED no modifica la naturaleza fiscal de los ingresos correspondientes a LA AGENCIA.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "4. Obligaciones fiscales de LA AGENCIA.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA será exclusivamente responsable de:", style: "body" },
  { text: "a) cumplir con sus obligaciones fiscales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) emitir los comprobantes fiscales que legalmente correspondan;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) presentar declaraciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) enterar contribuciones e impuestos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) mantener actualizada su información fiscal;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) conservar permisos, registros y documentación fiscal aplicable;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) atender requerimientos de autoridades fiscales relacionados con sus operaciones.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "5. Información fiscal.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA se obliga a proporcionar información fiscal verídica, actualizada y válida, incluyendo:", style: "body" },
  { text: "a) RFC;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) régimen fiscal;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) domicilio fiscal;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) constancia de situación fiscal;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) y cualquier otra documentación requerida para procesos de facturación o cumplimiento normativo.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "LA AGENCIA será responsable de cualquier error, omisión o inconsistencia en la información proporcionada.", style: "body" },
  { text: "6. Modificaciones regulatorias.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá modificar procesos relacionados con facturación, cobro, retención, emisión de CFDI, comprobación fiscal, cargos por servicio o administración de pagos cuando resulte necesario por:", style: "body" },
  { text: "a) cambios legislativos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) disposiciones fiscales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) criterios del SAT;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) resoluciones regulatorias;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) actualizaciones tecnológicas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) o cambios en el modelo operativo de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "7. Liberación de responsabilidad fiscal. LA AGENCIA libera y mantendrá en paz y a salvo a TOURSRED respecto de cualquier contingencia, diferencia, multa, sanción, crédito fiscal, reclamación o procedimiento derivado del incumplimiento de obligaciones fiscales atribuibles a LA AGENCIA.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "SÉPTIMA. CANCELACIONES, REEMBOLSOS Y COMPENSACIONES", style: "clauseTitle" },
  { text: "1. Política general de cancelaciones.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES reconocen que TOURSRED opera bajo un modelo de reservaciones con políticas estándar de cancelación aplicables a los tours publicados dentro de la plataforma, sin perjuicio de que determinados tours puedan clasificarse como \"No Cancelables\" conforme a las condiciones definidas por LA AGENCIA y autorizadas por TOURSRED.", style: "body" },
  { text: "2. Cancelaciones realizadas por el CLIENTE FINAL.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Salvo que el tour haya sido clasificado expresamente como \"No Cancelable\", las cancelaciones realizadas por el CLIENTE FINAL estarán sujetas a la siguiente política estándar de TOURSRED:", style: "body" },
  { text: "a.  Cancelaciones realizadas con 15 (quince) días naturales o más de anticipación al inicio del tour: El CLIENTE FINAL tendrá derecho al reembolso del 100% del monto aplicable mediante TOURSRED CASH.", style: "body" },
  { text: "b.  Cancelaciones realizadas entre 7 (siete) y 14 (catorce) días naturales antes del inicio del tour: El CLIENTE FINAL tendrá derecho al reembolso del 50% del monto aplicable mediante TOURSRED CASH. El 50% restante no reembolsado se distribuirá de la siguiente manera:", style: "body" },
  { text: "I. 60% corresponderá a LA AGENCIA como compensación operativa y administrativa derivada de la reservación cancelada;", style: "listRoman", margin: [40, 0, 0, 6] },
  { text: "II. 40% corresponderá a TOURSRED por concepto de intermediación, costos operativos, procesamiento, comercialización y afectación derivada de la cancelación.", style: "listRoman", margin: [40, 0, 0, 6] },
  { text: "III. Dicha distribución podrá ser aplicada mediante compensaciones internas, liquidaciones automáticas o ajustes operativos dentro de la plataforma. El 60% (sesenta por ciento) correspondiente a LA AGENCIA se aplicará como abono dentro de su liquidación ordinaria conforme a los mecanismos de pago previstos en la Cláusula Quinta del presente contrato.", style: "listRoman", margin: [40, 0, 0, 6] },
  { text: "c) Cancelaciones realizadas con menos de 7 (siete) días naturales de anticipación:", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "No generarán derecho a reembolso para el CLIENTE FINAL.", style: "body" },
  { text: "3. Tours no cancelables.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA podrá clasificar determinados tours, promociones, tarifas, experiencias o servicios como \"No Cancelables\", siempre que dicha condición:", style: "body" },
  { text: "a) sea claramente visible para el CLIENTE FINAL antes de finalizar la reservación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) cumpla con las políticas internas de TOURSRED;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) y no contravenga disposiciones legales aplicables.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "4. Forma de los reembolsos.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Salvo disposición legal aplicable o determinación expresa de TOURSRED, los reembolsos derivados de cancelaciones se realizarán preferentemente mediante TOURSRED CASH.", style: "body" },
  { text: "Únicamente en casos excepcionales determinados por TOURSRED, o cuando exista obligación legal aplicable, podrán realizarse devoluciones mediante transferencia bancaria u otro método distinto.", style: "body" },
  { text: "5. Cargo por servicio.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Los cargos por servicio, costos operativos, comisiones financieras o tarifas relacionadas con procesamiento de pagos no serán reembolsables.", style: "body" },
  { text: "No obstante, dichos cargos sí podrán ser reembolsados cuando la cancelación, incumplimiento o afectación derive de causas imputables a LA AGENCIA, incluyendo:", style: "body" },
  { text: "a) sobreventa;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) falta de disponibilidad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) cancelación imputable a LA AGENCIA;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) incumplimiento operativo;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) o imposibilidad de prestar el servicio confirmado.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "6. Cancelaciones imputables a LA AGENCIA.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Cuando LA AGENCIA cancele, incumpla o no pueda prestar un servicio previamente confirmado, el CLIENTE FINAL tendrá derecho al reembolso del 100% del monto efectivamente pagado, incluyendo cargos por servicio cuando resulten aplicables.", style: "body" },
  { text: "TOURSRED podrá realizar directamente dicho reembolso utilizando:", style: "body" },
  { text: "a) TOURSRED CASH;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) transferencias bancarias;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) compensaciones internas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) créditos promocionales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) o cualquier mecanismo operativo implementado por la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "LA AGENCIA autoriza expresamente a TOURSRED para descontar, compensar o retener dichos montos de futuras liquidaciones o saldos pendientes a su favor.", style: "body" },
  { text: "7. Fuerza mayor y caso fortuito.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Cuando existan eventos de fuerza mayor o caso fortuito que afecten la prestación del servicio, incluyendo fenómenos naturales, condiciones climáticas, cierres gubernamentales, bloqueos, disturbios, riesgos de seguridad, contingencias sanitarias o causas ajenas al control razonable de LAS PARTES, TOURSRED podrá priorizar, según corresponda:", style: "body" },
  { text: "a) la reprogramación del servicio;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) el otorgamiento de TOURSRED CASH;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) compensaciones internas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) o reembolsos parciales o totales según las circunstancias del caso.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "8. Compensaciones comerciales y goodwill.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá, de manera discrecional y sin que ello constituya obligación permanente, otorgar al CLIENTE FINAL:", style: "body" },
  { text: "a) créditos promocionales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) cupones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) puntos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) recompensas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) bonificaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) upgrades;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) o cualquier otra compensación comercial o de goodwill destinada a preservar la experiencia del usuario, reputación de la plataforma o resolución de incidencias.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "9. Facultades operativas de TOURSRED.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá establecer procesos, validaciones, tiempos de revisión, mecanismos operativos y políticas complementarias relacionadas con cancelaciones, reembolsos, compensaciones y resolución de disputas dentro de la plataforma.", style: "body" },
  { text: "OCTAVA. CONDUCTAS PROHIBIDAS Y USO INDEBIDO DE LA PLATAFORMA", style: "clauseTitle" },
  { text: "1. Uso adecuado de la plataforma.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA se obliga a utilizar la plataforma TOURSRED de manera legal, ética, responsable y conforme al presente contrato, políticas internas y legislación aplicable.", style: "body" },
  { text: "2. Conductas prohibidas.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA no podrá realizar, directa o indirectamente, cualquiera de las siguientes conductas:", style: "body" },
  { text: "a) publicar información falsa, engañosa o inexacta;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) manipular de forma fraudulenta o engañosa precios, disponibilidad, promociones, reservaciones o condiciones comerciales dentro de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) generar reservaciones simuladas, fraudulentas o artificiales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) utilizar métodos engañosos para alterar calificaciones, reputación o posicionamiento dentro de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) evadir comisiones o concretar operaciones fuera de la plataforma derivadas de contactos obtenidos mediante TOURSRED;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) solicitar pagos directos al CLIENTE FINAL respecto de montos, anticipos o conceptos que deban procesarse obligatoriamente a través de TOURSRED conforme al modelo operativo de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) utilizar la plataforma para actividades ilícitas, fraudulentas o contrarias a la legislación aplicable;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) vulnerar sistemas de seguridad, automatizaciones, integraciones o funcionalidades tecnológicas de TOURSRED;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) utilizar bots, automatizaciones no autorizadas, scraping, extracción masiva de información o herramientas que afecten la estabilidad de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) infringir derechos de propiedad intelectual de TOURSRED o terceros;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) utilizar marcas, identidad visual o reputación de TOURSRED de manera no autorizada;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "l) realizar prácticas discriminatorias, abusivas, ofensivas o contrarias a la experiencia del CLIENTE FINAL;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "m) incumplir reservaciones confirmadas de manera recurrente;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "n) generar afectaciones reputacionales graves a TOURSRED derivadas de malas prácticas operativas.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "3. Desviación de clientes y evasión de plataforma.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA reconoce que los CLIENTES FINALES obtenidos mediante TOURSRED forman parte del ecosistema comercial de la plataforma.", style: "body" },
  { text: "En consecuencia, LA AGENCIA se abstendrá de:", style: "body" },
  { text: "a) promover pagos externos respecto de conceptos que deban procesarse obligatoriamente mediante TOURSRED;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) redirigir clientes fuera de la plataforma con el propósito de evitar comisiones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) compartir medios de contacto con fines de evasión comercial;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) concretar operaciones paralelas derivadas de reservaciones originadas en TOURSRED sin autorización expresa de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) solicitar, inducir o presionar al CLIENTE FINAL para cancelar una reservación realizada dentro de TOURSRED con el propósito de concretar la operación de manera directa fuera de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "Dicha conducta será considerada una falta grave y podrá derivar en la suspensión inmediata de la cuenta de LA AGENCIA, cancelación definitiva de acceso a la plataforma, retención temporal de pagos pendientes y demás medidas operativas o legales que TOURSRED considere procedentes.", style: "body" },
  { text: "Lo anterior no será aplicable al cobro del saldo restante del TOUR no cubierto mediante el ANTICIPO, el cual podrá ser cobrado directamente por LA AGENCIA al CLIENTE FINAL conforme a lo establecido en la Cláusula Quinta del presente contrato. La prohibición señalada en este numeral se refiere exclusivamente a conductas mediante las cuales LA AGENCIA induzca, solicite o presione al CLIENTE FINAL a cancelar una RESERVACIÓN realizada dentro de la plataforma con el propósito de contratar el servicio de manera directa y evitar el pago del ANTICIPO o la COMISIÓN correspondiente a TOURSRED.", style: "body" },
  { text: "4. Facultades de monitoreo y validación.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá implementar mecanismos razonables de monitoreo, validación, análisis antifraude, revisión operativa, auditoría tecnológica y detección de riesgos para proteger la seguridad, estabilidad y correcto funcionamiento de la plataforma.", style: "body" },
  { text: "5. Medidas correctivas.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "En caso de detectar incumplimientos o conductas prohibidas, TOURSRED podrá, según la gravedad del caso:", style: "body" },
  { text: "a) emitir advertencias;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) limitar funcionalidades;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) suspender publicaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) retener pagos o liquidaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) cancelar promociones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) restringir temporalmente la cuenta;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) cancelar definitivamente la cuenta de LA AGENCIA;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) bloquear accesos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) o ejercer las acciones legales correspondientes.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "6. Responsabilidad por daños.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA será responsable de cualquier daño, perjuicio, reclamación, sanción, multa, pérdida económica o afectación reputacional ocasionada a TOURSRED derivada de conductas prohibidas o uso indebido de la plataforma.", style: "body" },
  { text: "NOVENA. RESPONSABILIDAD, LIMITACIONES Y LIBERACIÓN", style: "clauseTitle" },
  { text: "1. Naturaleza de intermediación.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES reconocen que TOURSRED opera exclusivamente como plataforma digital de intermediación y comercialización de servicios turísticos, por lo que no organiza, ejecuta, supervisa físicamente ni presta directamente los tours publicados por LA AGENCIA.", style: "body" },
  { text: "En consecuencia, LA AGENCIA será la única responsable frente al CLIENTE FINAL respecto de la operación y prestación efectiva de los servicios turísticos contratados.", style: "body" },
  { text: "2. Responsabilidad operativa de LA AGENCIA.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA será exclusivamente responsable de:", style: "body" },
  { text: "a) la correcta ejecución de los tours;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) seguridad de los CLIENTES FINALES;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) logística operativa;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) transportación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) guías, coordinadores y personal;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) cumplimiento de itinerarios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) calidad del servicio;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) permisos, seguros y autorizaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) atención de emergencias;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) cumplimiento normativo aplicable;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) y cualquier obligación derivada de la prestación de sus servicios turísticos.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "3. Limitación de responsabilidad de TOURSRED.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED no será responsable por:", style: "body" },
  { text: "a) accidentes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) lesiones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) pérdidas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) robos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) daños materiales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) retrasos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) cancelaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) incumplimientos operativos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) conductas de terceros;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) actos de proveedores;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) hechos atribuibles a LA AGENCIA;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "l) o cualquier situación derivada de la prestación efectiva del servicio turístico.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "4. Información publicada por LA AGENCIA.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED no garantiza la veracidad, exactitud o calidad de la información publicada por LA AGENCIA dentro de la plataforma, siendo esta última la única responsable del contenido publicado y de las condiciones ofrecidas al CLIENTE FINAL.", style: "body" },
  { text: "5. Fallas tecnológicas y disponibilidad de plataforma.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED procurará mantener la disponibilidad y funcionamiento razonable de la plataforma; sin embargo, no garantiza operación ininterrumpida ni libre de errores.", style: "body" },
  { text: "TOURSRED no será responsable por interrupciones temporales, fallas técnicas, mantenimientos, problemas de conectividad, ataques informáticos, errores de terceros, caídas de servicios externos o situaciones fuera de su control razonable.", style: "body" },
  { text: "6. Fuerza mayor y caso fortuito.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED no será responsable por incumplimientos, retrasos o afectaciones derivados de eventos de fuerza mayor o caso fortuito, incluyendo fenómenos naturales, contingencias sanitarias, disturbios, actos gubernamentales, cierres, bloqueos, fallas masivas de infraestructura, conflictos sociales o cualquier situación ajena a su control razonable.", style: "body" },
  { text: "7. Liberación y mantenimiento en paz y a salvo.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA libera y se obliga a mantener en paz y a salvo a TOURSRED, sus representantes, directivos, empleados, afiliados y proveedores respecto de cualquier reclamación, procedimiento, demanda, sanción, multa, daño, perjuicio o gasto derivado de:", style: "body" },
  { text: "a) la operación de los tours;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) incumplimientos de LA AGENCIA;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) actos u omisiones de su personal o proveedores;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) reclamaciones de CLIENTES FINALES;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) incumplimientos fiscales, laborales o regulatorios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) accidentes o afectaciones ocurridas durante la prestación de los servicios turísticos.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "8. Responsabilidad máxima de TOURSRED.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "En caso de que legalmente se determine responsabilidad directa de TOURSRED, esta quedará limitada, en la máxima medida permitida por la legislación aplicable, al monto efectivamente cobrado por TOURSRED como comisión respecto de la reservación específica que origine la reclamación.", style: "body" },
  { text: "DÉCIMA. PROPIEDAD INTELECTUAL Y USO DE CONTENIDO", style: "clauseTitle" },
  { text: "1. Propiedad intelectual de TOURSRED.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA reconoce que TOURSRED es titular o licenciatario legítimo de todos los derechos relacionados con la plataforma, incluyendo de manera enunciativa más no limitativa:", style: "body" },
  { text: "a) software;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) código fuente;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) diseño visual;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) interfaces;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) funcionalidades;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) bases de datos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) algoritmos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) procesos tecnológicos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) identidad gráfica;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) marcas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) logotipos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "l) nombres comerciales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "m) documentación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "n) desarrollos tecnológicos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "o) y demás elementos relacionados con la operación de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "El acceso a la plataforma no implica cesión, transmisión ni otorgamiento de derechos de propiedad intelectual a favor de LA AGENCIA.", style: "body" },
  { text: "2. Restricciones de uso.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA no podrá:", style: "body" },
  { text: "a) copiar, reproducir, modificar o distribuir elementos tecnológicos de TOURSRED;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) descompilar, alterar o intentar acceder al código fuente;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) replicar funcionalidades, modelos operativos o herramientas tecnológicas de TOURSRED;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) utilizar marcas, logotipos o identidad visual de TOURSRED sin autorización expresa;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) utilizar contenido o materiales de TOURSRED para fines distintos a la operación autorizada dentro de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "3. Propiedad del contenido de LA AGENCIA.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES reconocen que las fotografías, videos, descripciones, logotipos, itinerarios y demás contenido publicado por LA AGENCIA continuarán siendo propiedad de LA AGENCIA o de sus respectivos titulares.", style: "body" },
  { text: "No obstante, LA AGENCIA otorga a TOURSRED una autorización no exclusiva, gratuita, revocable y sin limitación territorial para utilizar dicho contenido con fines relacionados con:", style: "body" },
  { text: "a) operación de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) comercialización;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) promoción turística;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) campañas publicitarias;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) redes sociales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) posicionamiento digital;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) motores de búsqueda;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) programas de recompensas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) membresías;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) campañas de referidos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) afiliaciones comerciales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "l) y difusión general de los tours y servicios turísticos publicados.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "4. Garantía sobre contenido.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA declara y garantiza que cuenta con todos los derechos, permisos, autorizaciones y licencias necesarias respecto del contenido publicado dentro de TOURSRED.", style: "body" },
  { text: "LA AGENCIA será exclusivamente responsable de cualquier reclamación relacionada con:", style: "body" },
  { text: "a) derechos de autor;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) marcas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) propiedad intelectual;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) derechos de imagen;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) uso indebido de contenido;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) o cualquier violación de derechos de terceros.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "5. Facultades de TOURSRED.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá:", style: "body" },
  { text: "a) adaptar formatos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) optimizar imágenes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) ajustar contenido para fines técnicos o comerciales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) generar versiones promocionales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) traducir contenido;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) destacar publicaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) categorizar tours;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) y realizar ajustes razonables necesarios para la operación y promoción de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "Lo anterior no implicará modificación sustancial de la naturaleza del servicio ofrecido por LA AGENCIA.", style: "body" },
  { text: "6. Uso no autorizado de marca y reputación.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA se abstendrá de utilizar la marca, reputación, identidad visual o nombre comercial de TOURSRED para fines distintos a los autorizados por la plataforma o que puedan generar confusión, afectación reputacional o falsa representación comercial.", style: "body" },
  { text: "7. Supervivencia de derechos.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Las disposiciones relacionadas con propiedad intelectual, uso de contenido, confidencialidad y protección tecnológica continuarán vigentes aun después de la terminación de la relación contractual entre LAS PARTES.", style: "body" },
  { text: "DÉCIMA PRIMERA. PROTECCIÓN DE DATOS Y CONFIDENCIALIDAD", style: "clauseTitle" },
  { text: "1. Protección de datos personales.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES se obligan a cumplir con la legislación aplicable en materia de protección de datos personales, incluyendo la Ley Federal de Protección de Datos Personales en Posesión de los Particulares y demás disposiciones aplicables en los Estados Unidos Mexicanos.", style: "body" },
  { text: "2. Tratamiento de información.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá recopilar, almacenar, procesar, utilizar y administrar información relacionada con:", style: "body" },
  { text: "a) CLIENTES FINALES;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) reservaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) pagos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) operaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) actividad dentro de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) comportamiento transaccional;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) métricas operativas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) historial de uso;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) y demás información necesaria para la operación de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "Dicho tratamiento se realizará conforme al Aviso de Privacidad y políticas internas de TOURSRED.", style: "body" },
  { text: "3. Uso de información por LA AGENCIA.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA únicamente podrá utilizar la información de CLIENTES FINALES para fines directamente relacionados con:", style: "body" },
  { text: "a) operación del tour;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) logística;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) atención al cliente;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) cumplimiento de reservaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) soporte relacionado con el servicio contratado.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "LA AGENCIA se abstendrá de:", style: "body" },
  { text: "a) comercializar bases de datos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) transferir información a terceros sin autorización;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) utilizar información para fines ajenos a la reservación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) realizar campañas no autorizadas utilizando datos obtenidos mediante TOURSRED;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) utilizar información de CLIENTES FINALES para evadir la operación de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "4. Confidencialidad.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES reconocen como información confidencial toda aquella información técnica, comercial, operativa, financiera, estratégica o tecnológica a la que tengan acceso con motivo de la relación contractual, incluyendo de manera enunciativa más no limitativa:", style: "body" },
  { text: "a) bases de datos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) estrategias comerciales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) información financiera;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) procesos operativos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) información de clientes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) métricas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) documentación interna;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) modelos comerciales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) algoritmos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) desarrollos tecnológicos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) información no pública relacionada con TOURSRED.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "5. Obligaciones de confidencialidad.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES se obligan a:", style: "body" },
  { text: "a) mantener estricta confidencialidad respecto de la información recibida;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) utilizarla únicamente para fines relacionados con la ejecución del presente contrato;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) implementar medidas razonables de seguridad y resguardo;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) abstenerse de divulgar información a terceros no autorizados.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "6. Excepciones.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "No se considerará información confidencial aquella que:", style: "body" },
  { text: "a) sea de dominio público;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) haya sido obtenida legítimamente por terceros;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) deba revelarse por mandato de autoridad competente;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) o cuya divulgación sea requerida por disposición legal aplicable.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "7. Incidentes de seguridad.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA deberá notificar a TOURSRED de manera inmediata cualquier:", style: "body" },
  { text: "a) acceso no autorizado;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) vulneración de seguridad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) filtración de datos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) uso indebido de información;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) incidente tecnológico;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) o afectación relacionada con información de CLIENTES FINALES o de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "8. Supervivencia de obligaciones.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Las obligaciones de confidencialidad y protección de datos continuarán vigentes aun después de la terminación de la relación contractual entre LAS PARTES.", style: "body" },
  { text: "DÉCIMA SEGUNDA. SUSPENSIÓN, TERMINACIÓN Y BAJA DE LA PLATAFORMA", style: "clauseTitle" },
  { text: "1. Facultades de suspensión y restricción.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá suspender, limitar, restringir o bloquear temporalmente el acceso de LA AGENCIA a la plataforma cuando detecte o considere razonablemente la existencia de:", style: "body" },
  { text: "a) incumplimientos al presente contrato;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) conductas prohibidas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) actividades fraudulentas o sospechosas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) riesgos operativos, financieros o reputacionales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) afectaciones a CLIENTES FINALES;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) incumplimientos regulatorios o fiscales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) uso indebido de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) reclamaciones recurrentes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) incumplimientos operativos reiterados;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) sobreventas recurrentes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) evasión de comisiones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "l) manipulación fraudulenta de reservaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "m) vulneraciones de seguridad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "n) o cualquier situación que pueda afectar la estabilidad, seguridad o reputación de TOURSRED.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "2. Terminación de la relación contractual.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá cancelar definitivamente la cuenta de LA AGENCIA y dar por terminada la relación contractual de manera inmediata cuando:", style: "body" },
  { text: "a) exista fraude comprobado;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) LA AGENCIA promueva evasión deliberada de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) solicite a CLIENTES FINALES cancelar reservaciones para contratar directamente;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) exista uso ilegal de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) se detecten actividades que afecten gravemente la reputación de TOURSRED;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) LA AGENCIA reincida en incumplimientos graves;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) exista falsificación de documentación o información;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) se detecten riesgos legales, regulatorios o financieros relevantes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) o cuando la continuidad de LA AGENCIA represente un riesgo para la operación de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "3. Terminación sin causa.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Independientemente de las causales señaladas en el numeral anterior, TOURSRED podrá dar por terminada la relación contractual sin necesidad de invocar causa alguna, mediante aviso previo por escrito o por medios electrónicos con al menos 15 (quince) días naturales de anticipación, sin que ello genere responsabilidad ni indemnización a cargo de TOURSRED, salvo por las obligaciones pendientes derivadas de reservaciones confirmadas y no concluidas a la fecha de terminación.", style: "body" },
  { text: "4. Terminación voluntaria.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA podrá solicitar en cualquier momento la baja de su cuenta y terminación de la relación contractual, siempre que:", style: "body" },
  { text: "a) no existan reservaciones activas pendientes de ejecución;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) no existan disputas abiertas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) no existan adeudos pendientes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) y se encuentren concluidas las obligaciones operativas relacionadas con CLIENTES FINALES.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "5. Efectos de la suspensión o terminación.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "La suspensión o terminación podrá implicar:", style: "body" },
  { text: "a) bloqueo de accesos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) ocultamiento de publicaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) cancelación de promociones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) restricción de funcionalidades;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) retención temporal de pagos pendientes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) revisión de operaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) cancelación de reservaciones futuras cuando resulte necesario para proteger a CLIENTES FINALES o la operación de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "6. Retención y compensación de saldos.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá retener temporalmente saldos, liquidaciones o pagos pendientes de LA AGENCIA cuando:", style: "body" },
  { text: "a) existan disputas activas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) reclamaciones pendientes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) riesgos de fraude;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) reembolsos en proceso;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) posibles afectaciones a CLIENTES FINALES;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) incumplimientos contractuales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) o investigaciones relacionadas con operaciones realizadas dentro de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "TOURSRED podrá aplicar compensaciones, descuentos o retenciones conforme a lo establecido en el presente contrato.", style: "body" },
  { text: "7. Reservaciones activas.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "En caso de suspensión o terminación, TOURSRED podrá adoptar las medidas razonables necesarias para proteger a los CLIENTES FINALES con reservaciones activas, incluyendo:", style: "body" },
  { text: "a) reprogramaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) reembolsos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) compensaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) reasignación operativa cuando resulte posible;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) comunicación directa con los CLIENTES FINALES afectados.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "8. Conservación de información.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá conservar información, historiales operativos, reservaciones, registros financieros, documentación y evidencias relacionadas con LA AGENCIA durante el tiempo que resulte necesario para:", style: "body" },
  { text: "a) cumplimiento legal;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) obligaciones regulatorias;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) prevención de fraude;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) atención de reclamaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) auditorías;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) defensa jurídica;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) o cumplimiento de políticas internas.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "9. Supervivencia de obligaciones.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "La terminación de la relación contractual no extinguirá obligaciones pendientes relacionadas con:", style: "body" },
  { text: "a) pagos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) reembolsos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) reclamaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) confidencialidad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) protección de datos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) propiedad intelectual;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) obligaciones fiscales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) responsabilidades derivadas de reservaciones realizadas durante la vigencia del contrato.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "DÉCIMA TERCERA. MODIFICACIONES A LA PLATAFORMA, POLÍTICAS Y FUNCIONALIDADES", style: "clauseTitle" },
  { text: "1. Evolución de la plataforma.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA reconoce y acepta que TOURSRED es una plataforma tecnológica en constante evolución, por lo que TOURSRED podrá actualizar, modificar, incorporar, limitar, suspender o eliminar funcionalidades, herramientas, procesos, integraciones, diseños, módulos o características operativas de la plataforma.", style: "body" },
  { text: "2. Modificaciones operativas y comerciales.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá realizar ajustes relacionados con:", style: "body" },
  { text: "a) procesos operativos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) políticas internas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) medidas antifraude;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) funcionalidades tecnológicas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) herramientas de reservación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) sistemas de reputación;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) programas de recompensas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) membresías;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) TOURSRED CASH;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) campañas promocionales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) programas de referidos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "l) integraciones tecnológicas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "m) modelos de comisión;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "n) cargos por servicio;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "o) validaciones operativas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "p) procesos fiscales o regulatorios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "q) y cualquier otro aspecto relacionado con la operación de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "3. Notificación de cambios relevantes.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED procurará notificar a LA AGENCIA sobre modificaciones relevantes que impacten significativamente la operación de la plataforma mediante:", style: "body" },
  { text: "a) correo electrónico;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) notificaciones dentro de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) publicación de políticas actualizadas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) panel administrativo;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) o cualquier medio de comunicación razonablemente utilizado por TOURSRED.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "4. Aceptación de modificaciones.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "El uso continuo de la plataforma por parte de LA AGENCIA posterior a la entrada en vigor de modificaciones, políticas o actualizaciones constituirá aceptación de las mismas.", style: "body" },
  { text: "5. Cambios regulatorios o legales.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá implementar modificaciones inmediatas cuando resulten necesarias para cumplir con:", style: "body" },
  { text: "a) legislación aplicable;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) disposiciones fiscales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) requerimientos regulatorios;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) lineamientos de autoridades;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) medidas de seguridad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) prevención de fraude;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) cambios tecnológicos críticos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) o requerimientos de PASARELAS DE PAGO y proveedores tecnológicos.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "6. Nuevas funcionalidades y servicios.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá incorporar nuevos servicios, módulos, herramientas o funcionalidades relacionadas con:", style: "body" },
  { text: "a) inteligencia artificial;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) automatización;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) APIs;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) integraciones externas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) sistemas avanzados de comercialización;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) programas de afiliados;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) soluciones tecnológicas complementarias;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) o nuevas líneas de negocio compatibles con la operación de la plataforma.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "7. Limitación de responsabilidad por cambios.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED no será responsable por afectaciones derivadas de ajustes razonables, actualizaciones tecnológicas, mejoras operativas, cambios regulatorios o modificaciones necesarias para la evolución y seguridad de la plataforma, siempre que dichas modificaciones no impliquen incumplimientos legales aplicables.", style: "body" },
  { text: "DÉCIMA CUARTA. LEGISLACIÓN APLICABLE Y JURISDICCIÓN", style: "clauseTitle" },
  { text: "1. Legislación aplicable.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "El presente contrato se regirá e interpretará conforme a las leyes aplicables de los Estados Unidos Mexicanos, incluyendo legislación mercantil, civil, fiscal, tecnológica, de protección de datos personales y demás disposiciones aplicables relacionadas con la operación de la plataforma TOURSRED.", style: "body" },
  { text: "2. Resolución de controversias.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES acuerdan que cualquier controversia, reclamación, interpretación, incumplimiento o disputa derivada del presente contrato, de la operación de la plataforma o de la relación comercial entre LAS PARTES, procurará resolverse de buena fe mediante negociación directa entre LAS PARTES y/o los medios alternativos de solución de controversias.", style: "body" },
  { text: "En caso de no alcanzar un acuerdo entre LAS PARTES, se someterán a la siguiente:", style: "body" },
  { text: "Cláusula arbitral:", style: "body" },
  { text: "Todas las desavenencias que deriven de este contrato serán", style: "body" },
  { text: "resueltas definitivamente de acuerdo con las Reglas de Arbitraje del Centro de Arbitraje de México (CAM adoptadas por ARIAS México, por uno o más árbitros nombrados conforme a dichas Reglas. Cuando la controversia involucre un monto igual o superior a \\$100,000.00 (cien mil pesos 00/100 M.N.), el tribunal de arbitraje estará compuesto por tres árbitros; cuando el monto en controversia sea inferior a dicha cantidad, el arbitraje se sustanciará ante árbitro único. El arbitraje se llevará a cabo en español y tendrá lugar en Ciudad de México. Esta cláusula conservará su validez aun en caso de anulación del presente contrato.", style: "body" },
  { text: "3. Jurisdicción.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "En caso de no alcanzarse una solución amistosa, LAS PARTES se someten expresamente a la jurisdicción y competencia de los tribunales competentes de la Ciudad de México, renunciando expresamente a cualquier otro fuero que pudiera corresponderles por razón de sus domicilios presentes o futuros o por cualquier otra causa.", style: "body" },
  { text: "4. Idioma oficial.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "El idioma oficial del presente contrato será el español. Cualquier traducción, versión adaptada o interpretación en otro idioma tendrá únicamente fines informativos y no sustituirá la versión oficial en español.", style: "body" },
  { text: "5. Conservación electrónica de evidencia.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES reconocen que los registros electrónicos, bitácoras, logs, respaldos digitales, confirmaciones, notificaciones, accesos, aceptaciones electrónicas, comunicaciones realizadas dentro de la plataforma y demás evidencias digitales generadas por TOURSRED podrán utilizarse como medios de prueba válidos respecto de operaciones, reservaciones, pagos, aceptaciones y actividades realizadas dentro de la plataforma.", style: "body" },
  { text: "DÉCIMA QUINTA. FIRMA ELECTRÓNICA Y ACEPTACIÓN DIGITAL", style: "clauseTitle" },
  { text: "1. Validez de medios electrónicos.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES reconocen y aceptan que el presente contrato podrá celebrarse, aceptarse y formalizarse mediante medios electrónicos, digitales, tecnológicos o automatizados conforme a la legislación aplicable en los Estados Unidos Mexicanos.", style: "body" },
  { text: "2. Aceptación electrónica.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA reconoce y acepta que cualquiera de las siguientes acciones podrá constituir manifestación válida de consentimiento y aceptación del presente contrato:", style: "body" },
  { text: "a) registro dentro de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) creación de cuenta;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) aceptación mediante checkbox;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) autenticación electrónica;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) ingreso de códigos OTP;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) firma electrónica;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) acceso al panel administrativo;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) uso de funcionalidades de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) publicación de tours;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) aceptación digital de políticas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) o cualquier mecanismo electrónico implementado por TOURSRED.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "3. Equivalencia jurídica.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES reconocen que los medios electrónicos utilizados por TOURSRED producirán efectos jurídicos válidos conforme al Código de Comercio, legislación mercantil aplicable y demás disposiciones legales correspondientes en materia de comercio electrónico y mensajes de datos.", style: "body" },
  { text: "4. Evidencia electrónica.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES reconocen como medios de prueba válidos:", style: "body" },
  { text: "a) registros electrónicos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) logs de actividad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) direcciones IP;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) timestamps;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) bitácoras;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) confirmaciones electrónicas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) correos electrónicos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) comunicaciones dentro de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) registros de acceso;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "j) historial de operaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "k) respaldos digitales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "l) y cualquier evidencia tecnológica generada por TOURSRED.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "5. Comunicaciones electrónicas.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA acepta que TOURSRED podrá realizar comunicaciones, avisos, notificaciones, alertas, actualizaciones, requerimientos o información relacionada con la operación de la plataforma mediante:", style: "body" },
  { text: "a) correo electrónico;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) notificaciones dentro de la plataforma;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) panel administrativo;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) mensajes automatizados;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) aplicaciones móviles;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) SMS;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) WhatsApp;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) o cualquier medio electrónico proporcionado por LA AGENCIA.", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "6. Responsabilidad sobre medios de acceso.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA será responsable de todas las acciones realizadas mediante sus credenciales, usuarios, dispositivos, correos electrónicos o mecanismos de autenticación asociados a su cuenta dentro de la plataforma.", style: "body" },
  { text: "7. Conservación de evidencia digital.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "TOURSRED podrá conservar registros electrónicos, respaldos y evidencia digital relacionada con la aceptación del contrato, operaciones, reservaciones, pagos y actividad dentro de la plataforma durante el tiempo que resulte necesario para fines legales, regulatorios, operativos, fiscales o de seguridad.", style: "body" },
  { text: "CLÁUSULA DÉCIMA SEXTA. DISPOSICIONES GENERALES", style: "clauseTitle" },
  { text: "1. Integridad contractual.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "El presente contrato constituye el acuerdo total entre LAS PARTES respecto de la relación comercial y operación dentro de la plataforma TOURSRED, dejando sin efectos cualquier acuerdo, negociación, comunicación o entendimiento previo relacionado con su objeto.", style: "body" },
  { text: "2. Relación con políticas y documentos complementarios.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LAS PARTES reconocen que las políticas internas, lineamientos operativos, avisos, términos complementarios, reglas de uso, políticas de privacidad, políticas de cancelación y demás disposiciones publicadas por TOURSRED forman parte integral del presente contrato cuando resulten aplicables a la operación de la plataforma.", style: "body" },
  { text: "3. Nulidad parcial.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "En caso de que cualquier disposición del presente contrato sea declarada inválida, ilegal o inaplicable por autoridad competente, las demás disposiciones continuarán en pleno vigor y efecto en la máxima medida permitida por la legislación aplicable.", style: "body" },
  { text: "4. No renuncia de derechos.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "La falta de ejercicio o retraso por parte de TOURSRED respecto de cualquier derecho, facultad o acción derivada del presente contrato no constituirá renuncia a dicho derecho ni limitará su ejercicio posterior.", style: "body" },
  { text: "5. Cesión.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA no podrá ceder, transferir o delegar derechos u obligaciones derivados del presente contrato sin autorización previa y por escrito de TOURSRED.", style: "body" },
  { text: "TOURSRED podrá ceder o transferir total o parcialmente derechos u obligaciones relacionadas con la operación de la plataforma a empresas afiliadas, subsidiarias, adquirentes, inversionistas, sucesores o entidades relacionadas con procesos corporativos o comerciales.", style: "body" },
  { text: "6. Independencia de cláusulas.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Las cláusulas y disposiciones contenidas en el presente contrato deberán interpretarse de manera independiente entre sí.", style: "body" },
  { text: "7. Encabezados y estructura.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Los títulos, numeraciones y encabezados utilizados dentro del presente contrato tienen únicamente fines de orden y referencia, por lo que no limitarán ni afectarán la interpretación jurídica de sus disposiciones.", style: "body" },
  { text: "8. Supervivencia de obligaciones.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "Las obligaciones relacionadas con:", style: "body" },
  { text: "a) pagos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "b) reembolsos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "c) confidencialidad;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "d) protección de datos;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "e) propiedad intelectual;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "f) obligaciones fiscales;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "g) responsabilidades pendientes;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "h) reclamaciones;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "i) y resolución de disputas;", style: "listLetter", margin: [28, 0, 0, 6] },
  { text: "continuarán vigentes aun después de la terminación de la relación contractual entre LAS PARTES.", style: "body" },
  { text: "9. Actualización de información.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "LA AGENCIA será responsable de mantener actualizada toda la información relacionada con su operación, incluyendo datos fiscales, comerciales, bancarios, operativos y de contacto dentro de la plataforma.", style: "body" },
  { text: "10. Entrada en vigor.", style: "listNum", margin: [20, 0, 0, 6] },
  { text: "El presente contrato entrará en vigor a partir de la aceptación electrónica realizada por LA AGENCIA mediante cualquiera de los mecanismos autorizados por TOURSRED.", style: "body" },
  { text: "Leído que fue el presente contrato y enteradas LAS PARTES de su contenido, alcance y efectos legales, lo aceptan de conformidad mediante firma autógrafa, firma electrónica o aceptación digital a través de los mecanismos implementados por TOURSRED.", style: "body" },
  { text: "El presente contrato surtirá efectos legales a partir de la fecha de aceptación electrónica realizada por LA AGENCIA dentro de la plataforma.", style: "body" },
  { text: ["Firmado en la Ciudad de México, el día ", { text: data.fechaDia, bold: true }, " de ", { text: data.fechaMes, bold: true }, " de ", { text: data.fechaAnio, bold: true }], style: "body", margin: [0, 16, 0, 0] },

  { text: "ANEXO A.", style: "clauseTitle", pageBreak: "before" },
  { text: [{"text": "DEFINICIONES GENERALES", "bold": true}], style: "body" },
  { text: "Para efectos del presente contrato, los términos utilizados con mayúscula inicial tendrán el significado que se les atribuye a continuación:", style: "body" },
  { text: [{ text: "PLATAFORMA:  ", bold: true }, "Sistema digital operado por TOURSRED, incluyendo sitio web, aplicaciones, paneles administrativos, herramientas tecnológicas, sistemas de reservación y demás funcionalidades relacionadas con la publicación, promoción, comercialización y administración de tours y servicios turísticos."], style: "definition", margin: [0, 0, 0, 8] },
  { text: [{ text: "CLIENTE FINAL:  ", bold: true }, "Persona física o moral que realiza una reservación o contratación de servicios turísticos publicados por LA AGENCIA dentro de la plataforma TOURSRED."], style: "definition", margin: [0, 0, 0, 8] },
  { text: [{ text: "TOUR:  ", bold: true }, "Cualquier excursión, actividad, experiencia, traslado, circuito, servicio turístico, actividad recreativa o producto relacionado con turismo publicado por LA AGENCIA dentro de la plataforma."], style: "definition", margin: [0, 0, 0, 8] },
  { text: [{ text: "RESERVACIÓN:  ", bold: true }, "Solicitud confirmada de contratación de un TOUR realizada por un CLIENTE FINAL mediante la plataforma TOURSRED."], style: "definition", margin: [0, 0, 0, 8] },
  { text: [{ text: "ANTICIPO:  ", bold: true }, "Monto pagado por el CLIENTE FINAL a través de la plataforma TOURSRED al momento de confirmar una RESERVACIÓN, el cual será configurado por LA AGENCIA conforme al porcentaje mínimo y demás condiciones establecidas en la Cláusula Quinta del presente contrato, y de cuyo monto se descontará la COMISIÓN correspondiente a TOURSRED."], style: "definition", margin: [0, 0, 0, 8] },
  { text: [{ text: "COMISIÓN:  ", bold: true }, "Porcentaje, tarifa o contraprestación económica que TOURSRED cobra a LA AGENCIA por concepto de intermediación digital, comercialización y uso de la plataforma."], style: "definition", margin: [0, 0, 0, 8] },
  { text: [{ text: "TOURSRED CASH:  ", bold: true }, "Sistema interno de saldo electrónico, crédito virtual, monedero promocional o mecanismo digital de compensación operado por TOURSRED, utilizable exclusivamente dentro de la plataforma para la contratación de tours, servicios turísticos, promociones, bonificaciones, reembolsos, compensaciones o ajustes operativos autorizados por TOURSRED."], style: "definition", margin: [0, 0, 0, 8] },
  { text: "TOURSRED CASH no constituye cuenta bancaria, instrumento financiero, depósito monetario, inversión ni saldo retirable en efectivo, salvo que TOURSRED determine expresamente lo contrario mediante políticas internas publicadas en la plataforma.", style: "body" },
  { text: [{ text: "PASARELAS DE PAGO:  ", bold: true }, "Terceros autorizados para el procesamiento de pagos electrónicos, incluyendo bancos, adquirentes, agregadores, procesadores o plataformas financieras utilizadas por TOURSRED."], style: "definition", margin: [0, 0, 0, 8] },
  { text: [{ text: "POLÍTICAS DE PLATAFORMA:  ", bold: true }, "Lineamientos, reglas operativas, políticas comerciales, términos complementarios, manuales, criterios técnicos o disposiciones publicadas por TOURSRED dentro de la plataforma o comunicadas electrónicamente a LA AGENCIA."], style: "definition", margin: [0, 0, 0, 8] },
  { text: [{ text: "CONTENIDO:  ", bold: true }, "Toda información, imágenes, fotografías, videos, textos, descripciones, precios, itinerarios, disponibilidad, logotipos, material gráfico o cualquier otro elemento publicado por LA AGENCIA dentro de la plataforma."], style: "definition", margin: [0, 0, 0, 8] },
  { text: [{ text: "CONTRACARGO:  ", bold: true }, "Proceso mediante el cual un banco, institución financiera o procesador de pagos revierte, cancela o disputa un cargo previamente procesado, derivado de reclamaciones realizadas por el CLIENTE FINAL."], style: "definition", margin: [0, 0, 0, 8] },
      signatureBlock(data),
    ],
  };
}

/**
 * Genera el docDefinition para el contrato FIRMADO (con Anexo B lleno).
 * Se usa en verify-contract-otp después de validar el OTP.
 */
export function buildSignedContractDocDefinition(data: ContractData, anexo: AnexoBData) {
  const base = buildContractDocDefinition(data);
  return {
    ...base,
    content: [...base.content, ...anexoB(anexo)],
  };
}

/* ============================================================
 * USO EN LA EDGE FUNCTION (Deno) — validar esto primero con un 
 * documento de prueba antes de integrarlo en el flujo real:
 * ============================================================
 *
 * import PdfPrinter from "npm:pdfmake@0.2.x/js/printer.js";
 * import { buildContractDocDefinition } from "./contractDocDefinition.ts";
 *
 * const fonts = {
 *   Roboto: {
 *     normal: "npm:pdfmake@0.2.x/examples/fonts/Roboto-Regular.ttf",
 *     bold: "npm:pdfmake@0.2.x/examples/fonts/Roboto-Medium.ttf",
 *     italics: "npm:pdfmake@0.2.x/examples/fonts/Roboto-Italic.ttf",
 *     bolditalics: "npm:pdfmake@0.2.x/examples/fonts/Roboto-MediumItalic.ttf",
 *   },
 * };
 * // NOTA: pdfmake espera rutas de archivo o buffers de fuente reales —
 * // en Deno probablemente necesites descargar los .ttf de Roboto una vez
 * // y subirlos junto a la función, o usar fetch() para traerlos como
 * // ArrayBuffer al inicio. Esto es justo lo que hay que probar primero.
 *
 * const printer = new PdfPrinter(fonts);
 * const docDefinition = buildContractDocDefinition(data);
 * const pdfDoc = printer.createPdfKitDocument(docDefinition);
 *
 * const chunks: Uint8Array[] = [];
 * pdfDoc.on("data", (chunk: Uint8Array) => chunks.push(chunk));
 * const pdfBytes: Uint8Array = await new Promise((resolve) => {
 *   pdfDoc.on("end", () => resolve(new Uint8Array(
 *     chunks.reduce((acc, c) => [...acc, ...c], [] as number[])
 *   )));
 *   pdfDoc.end();
 * });
 *
 * // pdfBytes es lo que se hashea (crypto.subtle.digest) y se sube a Storage,
 * // exactamente con el mismo patrón que ya tienes en approve-agency-documents.
 */
